module RefModule(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] C  // Changed 'output' to 'output reg'
);integer obf_i, j;
    reg [15:0] sum;

    always @(*) begin
        sum = 0;
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
            if (B[obf_i] == 1) begin
                for (j = 0; j < 8; j = j + 1) begin
                    if (A[j] == 1) begin
                        sum = sum + (1 << (obf_i + j));
                    end
                end
            end
        end
        C = sum;
    end
endmodule
